sp_widget.client_script:
api.controller = function($scope, $http, $window, $location, glideUserSession, glideSystemProperties, spUtil, $timeout) {
    var c = this;

    // --- TraceNow UI Logic ---
    c.username = "";
    c.password = "";
    c.showPassword = false;
    c.togglePassword = function() {
        c.showPassword = !c.showPassword;
    };

    function showNotification(message, type) {
        if (typeof Toastify !== "undefined") {
            Toastify({
                text: message, duration: 3500, close: true, gravity: "top", position: "right",
                style: {
                    background: type === 'success' ? "linear-gradient(to right, #00b09b, #96c93d)" : "linear-gradient(to right, #ff5f6d, #ffc371)",
                    borderRadius: "8px", fontFamily: "Inter, sans-serif"
                }
            }).showToast();
        } else {
            type === 'success' ? spUtil.addTrivialMessage(message) : spUtil.addErrorMessage(message);
        }
    }

    // --- OOTB Enterprise Logic ---
    c.remember_me = c.data.forgetMe ? false : c.data.rememberMeDefault;
    c.data.url_suffix = $scope.portal ? $scope.portal.url_suffix : "";
    c.masked = true;

    // Handle Auto-SSO / Cert Login
    if (!c.data.is_logged_in && c.data.multisso_enabled && c.data.default_idp) {
        var pageId = $location.search().id || $scope.page.id;
        var isLoginPage = ($scope.portal.login_page_dv == pageId) || ('login' == pageId);
        c.server.get({ action: "set_sso_destination", pageURI: isLoginPage ? null : $location.url() }).then(function() {
            $window.location = "/login_with_sso.do?glide_sso_id=" + c.data.default_idp;
        });
    } else if (!c.data.is_logged_in && c.data.certAuthRedirect && c.data.cert_based_auth && c.data.certHeader == "true") {
        executeLogin(null, null, true);
    }

    // Main Login Trigger
    c.login = function(username, password, isCertLogin) {
        if (!username || !password) {
            showNotification("Please enter both username and password.", "error");
            return;
        }
        executeLogin(username, password, isCertLogin);
    };

    function executeLogin(username, password, isCertLogin) {
        var url = spUtil.getURL({sysparm_type: 'view_form.login'});
        var pageId = $location.search().id || $scope.page.id;
        var isLoginPage = ($scope.portal.login_page_dv == pageId) || ('login' == pageId);

        return $http({
            method: 'post',
            url: url,
            data: $.param({
                'sysparm_type': 'login',
                'ni.nolog.user_password': true,
                'remember_me': !!c.remember_me ? true : false,
                'user_name': username,
                'user_password': password,
                'get_redirect_url': true,
                'is_direct_redirect': true,
                'sysparm_goto_url': isLoginPage ? null : $location.url(),
                'mfa_redirect_url': isLoginPage ? null : c.data.pageURI,
                'cert_login' : !!isCertLogin
            }),
            headers: {'Content-Type': 'application/x-www-form-urlencoded'}
        }).then(function(response) {
            if (!response.data) {
                showNotification(c.data.errorMsg, "error");
                return;
            }

            if (response.data.status == 'success') {
                // --- TRACENOW CUSTOM INJECTION: Verify Admin BEFORE routing ---
                c.server.get({ action: "verify_admin" }).then(function(server_response) {
                    if (server_response.data.isAdmin) {
                        showNotification("Login successful. Redirecting to your workspace...", "success");

                        // Proceed with MFA check or final routing
                        if (c.data.multiFactorAuthEnabled) {
                            if(response.data.session_token) window.g_ck = response.data.session_token;
                            c.server.get({
                                action: "multi_factor_auth_setup", directTo: "?id=tracennow_dashboard"
                            }).then(handleLoginResponse.bind(response), handleLoginResponse.bind(response));
                        } else {
                            handleLoginResponse.call(response);
                        }
                    } else {
                        // Valid credentials, but NOT an admin. Logout immediately.
                        $http.post('/api/now/sp/logout').then(function() {
                            showNotification("Access Denied: You must be an administrator to access this portal.", "error");
                            c.password = "";
                        });
                    }
                });

            } else if (response.data.status == 'mfa_code_required') {
                $window.location = '/validate_multifactor_auth_code.do';
            } else {
                showNotification(response.data.message || "Invalid username or password.", "error");
                c.password = "";
                c.username = "";
            }
        }, function errorCallback(response) {
            showNotification(c.data.errorMsg, "error");
        });
    }

    function handleLoginResponse() {
        // Route directly to custom dashboard after successful OOTB auth
        $timeout(function() {
            $window.location = "?id=tracennow_dashboard"; 
        }, 1500);
    }
};

sp_widget.css:
/* TraceNow Login Widget CSS */
:root {
  --primary: #116AF8;
  --secondary: #0A50F5;
  --accent: #9BC0FC;
  --bg: #f4f8fd;
  --text: #0f172a;
  --muted: #64748b;
  --white: #fff;
  --radius: 18px;
  --shadow: 0 20px 60px rgba(17,106,248,.12);
}

* { box-sizing: border-box; margin: 0; padding: 0; }
html, body, .tn-login-page { height: 100%; }
body {
  font-family: Inter, "Segoe UI", Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
}

.tn-login-page {
  display: flex;
  min-height: 100vh;
}

.tn-left {
  flex: 1;
  position: relative;
  overflow: hidden;
  color: #fff;
  padding: 56px;
  background: radial-gradient(circle at top right, rgba(255,255,255,.18), transparent 35%), linear-gradient(135deg, #116AF8 0%, #0A50F5 100%);
  display: flex;
  flex-direction: column;
}

.tn-logo {
  display: flex;
  align-items: center;
  gap: 12px;
  z-index: 2;
}

.tn-watermark {
    position: absolute;
    transform: translateY(-50%);
    width: 520px;
    height: 520px;
    right: -5px;
    top: 52%;
    opacity: .06;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none;
    z-index: 1;
}

.tn-watermark svg {
    width: 100%;
    height: auto;
}

.tn-content {
  max-width: 560px;
  margin: auto 0;
  z-index: 2;
}

.tn-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 18px;
  border-radius: 999px;
  background: rgba(255,255,255,.15);
  margin-bottom: 28px;
  font-size: 14px;
}

.dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: #8bffb8;
}

.tn-content h1 {
  font-size: 56px;
  line-height: 1.1;
  font-weight: 800;
  margin-bottom: 24px;
}

.tn-content p {
  font-size: 18px;
  line-height: 1.8;
  color: rgba(255,255,255,.92);
  margin-bottom: 48px;
}

.tn-stats {
  display: flex;
  gap: 48px;
}

.tn-stats h2 {
  font-size: 34px;
  margin-bottom: 6px;
}

.tn-stats span {
  color: rgba(255,255,255,.82);
}

.tn-footer {
  margin-top: auto;
  color: rgba(255,255,255,.8);
}

.tn-right {
  width: 42%;
  min-width: 520px;
  background: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 48px;
}

.login-wrapper {
  width: 100%;
  max-width: 440px;
}

.login-wrapper h1 {
  font-size: 40px;
  margin-bottom: 8px;
}

.subtitle {
  color: var(--muted);
  margin-bottom: 36px;
}

.form-group { margin-bottom: 24px; }
label {
  display: block;
  margin-bottom: 10px;
  font-weight: 600;
}

input[type=text],
input[type=password] {
  width: 100%;
  height: 56px;
  border: 1px solid #d7e1ef;
  border-radius: 14px;
  padding: 0 18px;
  font-size: 15px;
}

.password-wrapper { position: relative; }
.eye {
  position: absolute;
  right: 16px;
  top: 50%;
  transform: translateY(-50%);
  border: 0;
  background: none;
  cursor: pointer;
}

.login-btn {
  width: 100%;
  height: 58px;
  border: 0;
  border-radius: 14px;
  background: linear-gradient(135deg, #116AF8, #0A50F5);
  color: #fff;
  font-size: 17px;
  font-weight: 700;
  cursor: pointer;
  margin-top: 12px;
  box-shadow: var(--shadow);
}

.security-card {
  margin-top: 28px;
  padding: 18px;
  border-radius: 16px;
  background: #f7faff;
  border: 1px solid #dce8fb;
}

.legal {
  margin-top: 28px;
  text-align: center;
  color: var(--muted);
  font-size: 14px;
}

@media(max-width:991px) {
  .tn-login-page { flex-direction: column; }
  .tn-right {
    width: 100%;
    min-width: 0;
  }
  .tn-content h1 { font-size: 42px; }
  .tn-stats { gap: 24px; flex-wrap: wrap; }
}

.tn-logo,
.tn-content,
.tn-footer {
    position: relative;
    z-index: 2;
}

sp_widget.script:
(function() {
    options.show_panel = options.show_panel == "true" || options.show_panel == true;

    // --- TraceNow Custom Admin Check ---
    if (input && input.action === "verify_admin") {
        var roleCheck = new GlideRecordSecure('sys_user_has_role');
        roleCheck.addQuery('user', gs.getUserID());
        roleCheck.addQuery('role.name', 'admin');
        roleCheck.setLimit(1);
        roleCheck.query();
        data.isAdmin = roleCheck.hasNext();
        return;
    }

    // --- OOTB Enterprise Logic ---
    if (input && input.action === "multi_factor_auth_setup") {
        if (gs.getSession().getProperty("setup_multifactor_authn")) {
            gs.getSession().putProperty("nav_to", input.directTo);
            gs.getSession().putProperty("starting_page", input.directTo);
            gs.getSession().putProperty("is_direct_redirect", "true");
        }
        return;
    }

    var ssoSelectorField = gs.getProperty('glide.authenticate.multisso.login_locate.user_field', 'user_name');
    var gr = new GlideRecordSecure('sys_user');
    if (gr.isValidField(ssoSelectorField)) {
        data.ssoSelectorFieldLabel = gr.getElement(ssoSelectorField).getLabel();
    }

    if (input && input.action === "set_sso_destination") {
        var gs_nav_to = gs.getSession().getProperty("nav_to");
        gs.getSession().putProperty("nav_to", null);
        if (input.pageURI) {
            gs.getSession().putProperty("is_direct_redirect", "true");
            gs.getSession().putProperty("starting_page", input.pageURI);
        } else if (!gs.getSession().getProperty("starting_page") && gs_nav_to) {
            gs.getSession().putProperty("starting_page", gs_nav_to);
        }
        return;
    }

    var portalRecord = $sp.getPortalRecord();
    var self_registration_field = portalRecord ? portalRecord.getValue("user_registration_config") : "";
    if (self_registration_field) {
        var registration_config = new GlideRecordSecure("sys_user_registration_config");
        registration_config.addActiveQuery();
        registration_config.query('sys_id', self_registration_field);
        if (registration_config.next()) {
            data.self_registration_record_producer = registration_config.getValue("record_producer");
            data.self_registration_label = registration_config.getValue("registration_label") || gs.getMessage("Sign Up");
        }
    }

    // Certificate based authentication
    if (portalRecord && (portalRecord.getValue('enable_certificate_based_authentication') == 1)) {
        data.cert_based_auth = gs.getProperty('glide.authenticate.mutual.enabled', 'false') == 'true';
    }

    if (data.cert_based_auth) {
        data.certHeader = "false";
        try {
            var trans = GlideTransaction.getValue();
            if (trans) {
                var request = trans.getRequest();
                if (request && request.getHeader("X-Client-Cert")) {
                    data.certHeader = "true";
                }
            }
        } catch(e) {}
    }

    data.isShowLoginWithIdps = false;
    data.isMultiSSOActive = gs.getProperty('glide.authenticate.multisso.enabled', 'false') == 'true';
    var ssoProps = new GlideRecordSecure("sso_properties");
    if (data.isMultiSSOActive && ssoProps.isValid()) {
        try {
            var ssoUtil = new MultiSSO_OidcUtil(); 
            data.ssoRecords = ssoUtil.getSSORecords();
            data.isShowLoginWithIdps = (data.ssoRecords.length > 0);
        } catch (e) {}
    }    

    data.pswdResetUrl = gs.getProperty('glide.security.password_reset.uri');
    data.forgotPwdLinkProp = gs.getProperty('glide.security.forgot_password.display.link');
    data.errorMsg = gs.getMessage("There was an error processing your request");
    data.errorMsg2 = gs.getMessage("An error has occurred - please contact your system administrator");
    data.passwordMsg = gs.getMessage("Password");
    data.usernameMsg = gs.getMessage("User name");

    // SCOPED SAFE REPLACEMENTS: gs.getProperty returns strings, so we check for 'true'
    data.forgetMe = (gs.getProperty("glide.ui.forgetme", "false") === "true");
    data.rememberMeDefault = (gs.getProperty('glide.ui.remember.me.default', "true") === "true");
    data.is_logged_in = gs.getSession().isLoggedIn();

    var bypass_sso = options.bypass_sso == "true";
    data.multisso_enabled = !bypass_sso && (gs.getProperty("glide.authenticate.multisso.enabled", "false") === "true");
    data.default_idp = gs.getProperty("glide.authenticate.sso.redirect.idp") || '';

    // Scoped Safe URI grabber
    data.pageURI = $sp.getParameter('id') ? '?id=' + $sp.getParameter('id') : '';

    data.multiFactorAuthEnabled = (gs.getProperty('glide.authenticate.multifactor', "false") === "true");
    data.certAuthRedirect = gs.getProperty('glide.authenticate.cert.redirect.enable', 'false') === 'true';

    var customURL = (gs.getProperty('glide.customurl.enabled', "false") === "true");
    if (customURL == true && data.multisso_enabled == true) {
        try {
            var idp = SNC.CustomURLSPUtil.getAutoRedirectIDPForCustomURLWithPortal();
            // Scoped Safe String check
            if(idp !== null && idp !== undefined && idp !== '') {
                data.default_idp = idp;
            }
        } catch(e) {}
    }

    var session = gs.getSession();
    var isSessionAccessReduced = false;
    var isSessionAccessMessageShown = false;

    if (session) {
        // Fallback for scope if these properties aren't accessible
        try {
            isSessionAccessReduced = session.getBooleanProperty("isSessionAccessReduced", false);
            isSessionAccessMessageShown = session.getBooleanProperty("isSessionAccessReducedMessageShown", false);
        } catch(e) {}
    }

    if (isSessionAccessReduced && !isSessionAccessMessageShown) {
        try {
            SNC.SessionAccessUtil.showUserInfoMessageIfAccessReduced();
        } catch(e) {}
    }
})();
